<?php require 'config.php'; require_role('teacher'); $id=(int)($_GET['id']??0); $st=$pdo->prepare('SELECT * FROM submissions WHERE id=?'); $st->execute([$id]); $s=$st->fetch(); if(!$s) die('Submission not found'); $path=UPLOAD_DIR.$s['stored_name']; if(!is_file($path)) die('File missing'); header('Content-Type: application/octet-stream'); header('Content-Disposition: attachment; filename="'.basename($s['file_name']).'"'); header('Content-Length: '.filesize($path)); readfile($path); exit;
